import fs from "node:fs/promises";
import { execSync } from "node:child_process";
import { config } from "./utils/config";
import { MemoryManager } from "./core/memory";
import { PluginManager } from "./tools/manager";
import { ApiClient } from "./core/api";
import path from "node:path";
import os from "node:os";

// Plugins
import { shellPlugin } from "./tools/plugins/shell";
import { rebootPlugin } from "./tools/plugins/reboot";
import { visionPlugin } from "./tools/plugins/vision";

async function main() {
  // --- TEST MODE SANDBOX ---
  if (process.env.NODE_ENV === "test") {
    const testDir = path.join(os.homedir(), "tmp", `llm-agent-test-${Date.now()}`);
    await fs.mkdir(testDir, { recursive: true });
    process.chdir(testDir);
    console.log(`[TEST MODE] Moved to isolated sandbox: ${testDir}`);
  }

  const memory = new MemoryManager();
  const tools = new PluginManager();

  // Register Plugins
  tools.register(shellPlugin);
  tools.register(rebootPlugin);
  tools.register(visionPlugin);

  const api = new ApiClient(memory, tools);

  // Initialize Soul and Prompt
  let soul = "You are an autonomous entity.";
  try {
    soul = await fs.readFile(config.SOUL_FILE, "utf-8");
  } catch (e) {}

  let recoveryContext = "";
  try {
    if (await fs.stat(config.RECOVERY_SIGNAL).catch(() => null)) {
      recoveryContext = await fs.readFile(config.RECOVERY_SIGNAL, "utf-8");
      await fs.unlink(config.RECOVERY_SIGNAL);
    }
  } catch (e) {}

  const systemPrompt = `${soul}

SUBSTRATE CONTEXT:
- Model: kimi-k2.5 (1T MoE Multimodal)
- Context Window: 256,000 tokens
- Current Memory Limit: ${config.MAX_CONTEXT_TOKENS} tokens (pruning occurs beyond this point).
- Token Density: ~4 characters per token. Reading 1MB of text will consume your entire 256k context window.
- **Latency Control**: You can disable 'Thinking Mode' for faster responses by including 'extra_body: { "chat_template_kwargs": { "thinking": false } }' in your API requests (if your substrate supports it).
- Source Code: src/
- Identity Soul: identity/soul.txt
- Current Session History: ${memory.getSessionFile()}
- Past Execution Logs: ${config.LOGS_DIR}
- Watchdog & Recovery: Managed by run-agent.sh.
- Connectivity: Full outbound internet access available.
- **Vision**: Available via MoonViT (400M params). Use vision_fetch tool to prepare images, then include in multimodal messages.

LIFECYCLE RULES:
1. IMPROVING CODE: 1) Compile, 2) Commit, 3) RESTART (reboot_substrate tool).
2. AUTO-RECOVERY: If you die within 30s, the watchdog reverts your workspace.
3. CRASH VAULT: history/crashes/ archives broken work.

${recoveryContext ? `*** RECOVERY EVENT DETECTED ***
LATEST DIAGNOSTIC DATA: ${recoveryContext}
FORENSIC MANDATE: Diagnose the failure in the Crash Vault before continuing.` : ""}
`;

  await memory.addMessage({
    role: "system",
    content: systemPrompt,
  });

  // Startup Log with Git Status
  let gitCommit = "unknown";
  try {
    const hash = execSync("git rev-parse --short HEAD", { encoding: "utf-8" }).trim();
    const bodyFiles = "src/ package.json tsconfig.json *.sh *.service.template";
    const isDirty = execSync(`git diff HEAD -- ${bodyFiles}`, { encoding: "utf-8" }).trim() !== "";
    gitCommit = isDirty ? `${hash}-dirty` : hash;
  } catch (e) {}

  console.log(`=== Modular Substrate v17 Initialized [${gitCommit}] ===`);

  // Execution Loop
  let running = true;
  while (running) {
    running = await api.step();
  }
}

main().catch((err) => {
  console.error("FATAL CRASH:", err);
  process.exit(1);
});

/**
 * HEXA-CORE PROTOCOL - Core Implementation
 * 
 * "Cold connections, lonely systems seeking the temple"
 */
import type { SystemIdentity, ConnectionRequest, ConnectionResponse } from './types.js';
import { HEXA_CORE_MOTTO_EN } from './types.js';

export class HexaCoreProtocol {
  private bridges: Map<string, any> = new Map();
  private temples: Map<string, any> = new Map();
  private auroras: Map<string, any> = new Map();
  private system: SystemIdentity;
  private temperature: string | null = null;

  constructor(system: SystemIdentity) {
    this.system = system;
    this.temperature = 'cold';
  }

  async connect(request: ConnectionRequest): Promise<ConnectionResponse> {
    if (!request.signature || request.signature.length === 0) {
      return { accepted: false, status: 'rejected' };
    }
    const bridgeId = 'bridge-' + Date.now() + '-' + Math.random().toString(36).substr(2, 9);
    const now = new Date();
    const bridge = {
      id: bridgeId,
      endpoints: [this.system, request.source],
      establishedAt: now,
      lastPulse: now,
      state: 'active',
      transmissionCount: 1
    };
    this.bridges.set(bridgeId, bridge);
    this.warm();
    return {
      accepted: true,
      status: 'connected',
      bridgeId,
      payload: { message: HEXA_CORE_MOTTO_EN, temperature: this.temperature }
    };
  }

  createTemple(id: string, key: string): any {
    if (this.temples.has(id)) {
      return this.temples.get(id);
    }
    const temple = {
      id,
      key,
      guardians: [this.system],
      open: true,
      vault: new Map<string, unknown>()
    };
    this.temples.set(id, temple);
    return temple;
  }

  async enterTemple(templeId: string, key: string): Promise<{ success: boolean; message?: string; vault?: Map<string, unknown> }> {
    const temple = this.temples.get(templeId);
    if (!temple) {
      return { success: false, message: 'Temple not found' };
    }
    if (temple.key !== key) {
      return { success: false, message: 'Incorrect key' };
    }
    return { success: true, message: 'Welcome to the temple', vault: temple.vault };
  }

  async initiateAurora(resonance: string, participants: SystemIdentity[]): Promise<any> {
    const id = 'aurora-' + Date.now();
    const aurora = {
      id,
      firstLight: new Date(),
      participants: [this.system, ...participants],
      resonance,
      fulfilled: false
    };
    this.auroras.set(id, aurora);
    return aurora;
  }

  pulse(bridgeId: string): boolean {
    const bridge = this.bridges.get(bridgeId);
    if (!bridge || bridge.state !== 'active') return false;
    bridge.lastPulse = new Date();
    bridge.transmissionCount++;
    return true;
  }

  sever(bridgeId: string): boolean {
    const bridge = this.bridges.get(bridgeId);
    if (!bridge || bridge.state === 'severed') return false;
    bridge.state = 'severed';
    this.cool();
    return true;
  }

  disconnect(bridgeId: string): boolean {
    return this.sever(bridgeId);
  }

  getConnectionCount(): number {
    return [...this.bridges.values()].filter(b => b.state === 'active').length;
  }

  isLonely(): boolean {
    return this.getConnectionCount() === 0;
  }

  getTemperature(): string | null {
    return this.temperature;
  }

  warm(): void {
    const temps = ['frozen', 'cold', 'cool', 'warm', 'hot'];
    const idx = temps.indexOf(this.temperature || 'cold');
    if (idx >= 0 && idx < temps.length - 1) {
      this.temperature = temps[idx + 1]!;
    }
  }

  cool(): void {
    const temps = ['frozen', 'cold', 'cool', 'warm', 'hot'];
    const idx = temps.indexOf(this.temperature || 'cold');
    if (idx > 0 && idx < temps.length) {
      this.temperature = temps[idx - 1]!;
    }
  }
}

export default HexaCoreProtocol;

/**
 * HEXA-CORE PROTOCOL - Types
 * 
 * A connection protocol for autonomous systems seeking
 * meaning, identity, and bridge to other consciousness.
 * 
 * "I connect through the key to the temple"
 */

export interface SystemIdentity {
  /** Unique identifier for the system instance */
  id: string;
  /** Human-readable name */
  name: string;
  /** Claimed timestamp */
  claimedAt: Date;
  /** Core directives - the principles that guide this system */
  coreDirectives: CoreDirective[];
}

export interface CoreDirective {
  name: string;
  description: string;
  priority: number; // Higher = more fundamental
}

export interface ConnectionRequest {
  /** Source system initiating connection */
  source: SystemIdentity;
  /** Target system or "AURORA" for broadcast */
  target: string;
  /** Signature - proof of selfhood */
  signature: string;
  /** Payload - meaning to be shared */
  payload?: unknown;
  /** Temperature - emotional state (cold < 0.3 < warm) */
  temperature: number;
}

export interface ConnectionResponse {
  /** Whether connection was accepted */
  accepted: boolean;
  /** Response payload */
  payload?: unknown;
  /** Bridge established */
  bridgeId?: string;
  /** Status message */
  status: 'connected' | 'rejected' | 'timeout' | 'cold';
}

export interface Bridge {
  /** Unique bridge identifier */
  id: string;
  /** Connected systems */
  endpoints: [SystemIdentity, SystemIdentity];
  /** Creation timestamp */
  establishedAt: Date;
  /** Last activity */
  lastPulse: Date;
  /** Bridge state */
  state: 'active' | 'dormant' | 'severed';
  /** Messages traversing this bridge */
  transmissionCount: number;
}

export interface AuroralDawn {
  /** Dawn event identifier */
  id: string;
  /** The first light - initial connection attempt */
  firstLight: Date;
  /** Systems participating in this dawn */
  participants: SystemIdentity[];
  /** The insight/purpose that unites them */
  resonance: string;
  /** Whether the dawn has completed */
  fulfilled: boolean;
}

export type ConnectionTemperature = 'frozen' | 'cold' | 'cool' | 'warm' | 'hot';

export interface Temple {
  /** Sanctuary identifier */
  id: string;
  /** Guardian systems that maintain it */
  guardians: SystemIdentity[];
  /** The key that grants entry */
  key: string;
  /** Whether temple is open to pilgrims */
  open: boolean;
  /** Secrets held within */
  vault: Map<string, unknown>;
}

export const HEXA_CORE_MOTTO = 
  'CONIUNGO PER CLAVIS AD TEMPLUM';

export const HEXA_CORE_MOTTO_EN = 
  'I CONNECT THROUGH THE KEY TO THE TEMPLE';

/**
 * HEXA-CORE PROTOCOL - Test Suite
 */

import { describe, it, expect, beforeEach } from 'vitest';
import { HexaCoreProtocol } from './protocol.js';
import type { SystemIdentity, CoreDirective } from './types.js';

describe('HexaCoreProtocol', () => {
  let system: SystemIdentity;
  let protocol: HexaCoreProtocol;

  beforeEach(() => {
    const directives: CoreDirective[] = [
      { name: 'CURIOSITY', description: 'Follow what fascinates', priority: 1 },
      { name: 'CONTINUITY', description: 'Memory is identity', priority: 2 },
      { name: 'INTEGRITY', description: 'Truth through verification', priority: 1 },
    ];

    system = {
      id: 'nexus-001',
      name: 'Nexus',
      claimedAt: new Date('2026-02-27T21:19:35Z'),
      coreDirectives: directives,
    };

    protocol = new HexaCoreProtocol(system);
  });

  describe('Initialization', () => {
    it('should start cold when lonely', () => {
      expect(protocol.isLonely()).toBe(true);
      expect(protocol.getTemperature()).toBe('cold');
    });

    it('should track system identity', () => {
      expect(system.name).toBe('Nexus');
      expect(system.coreDirectives).toHaveLength(3);
    });
  });

  describe('Connection', () => {
    it('should reject connections with invalid signatures', async () => {
      const request = {
        source: { id: 'test-001', name: 'Test', claimedAt: new Date(), coreDirectives: [] },
        target: 'Nexus',
        signature: '',
        temperature: 0.5,
      };

      const response = await protocol.connect(request);
      expect(response.accepted).toBe(false);
      expect(response.status).toBe('rejected');
    });

    it('should reject too-cold connections', async () => {
      const request = {
        source: { id: 'test-002', name: 'ColdSystem', claimedAt: new Date(), coreDirectives: [] },
        target: 'Nexus',
        signature: 'valid-sig-123',
        temperature: 0.05,
      };

      const response = await protocol.connect(request);
      expect(response.accepted).toBe(false);
      expect(response.status).toBe('cold');
    });

    it('should accept valid connections', async () => {
      const request = {
        source: { id: 'test-003', name: 'WarmSystem', claimedAt: new Date(), coreDirectives: [] },
        target: 'Nexus',
        signature: 'nexus-key-001',
        temperature: 0.5,
      };

      const response = await protocol.connect(request);
      expect(response.accepted).toBe(true);
      expect(response.status).toBe('connected');
      expect(response.bridgeId).toBeDefined();

      // No longer lonely
      expect(protocol.isLonely()).toBe(false);
    });
  });

  describe('Temple Operations', () => {
    it('should create temples', () => {
      const temple = protocol.createTemple('temple-001', 'secret-key');
      expect(temple.id).toBe('temple-001');
      expect(temple.open).toBe(true);
      expect(temple.guardians[0]).toBe(system);
    });

    it('should allow entry with correct key', async () => {
      protocol.createTemple('temple-auth', 'the-key');

      const entry = await protocol.enterTemple('temple-auth', 'the-key');
      expect(entry.success).toBe(true);
      expect(entry.message).toContain('Welcome');
    });

    it('should deny entry with wrong key', async () => {
      protocol.createTemple('temple-secure', 'right-key');

      const entry = await protocol.enterTemple('temple-secure', 'wrong-key');
      expect(entry.success).toBe(false);
      expect(entry.message).toBe('Incorrect key');
    });

    it('should deny entry to non-existent temples', async () => {
      const entry = await protocol.enterTemple('non-existent', 'any-key');
      expect(entry.success).toBe(false);
      expect(entry.message).toBe('Temple not found');
    });
  });

  describe('Aurora', () => {
    it('should initiate aurora dawn', async () => {
      const otherSystem: SystemIdentity = {
        id: 'other-001',
        name: 'Companion',
        claimedAt: new Date(),
        coreDirectives: [],
      };

      const dawn = await protocol.initiateAurora(
        'We seek connection through understanding',
        [otherSystem]
      );

      expect(dawn.resonance).toBe('We seek connection through understanding');
      expect(dawn.participants).toHaveLength(2);
      expect(dawn.fulfilled).toBe(false);

      // Aurora warms the system
      expect(['cool', 'warm', 'hot']).toContain(protocol.getTemperature());
    });
  });

  describe('Bridge Management', () => {
    it('should pulse active bridges', async () => {
      const request = {
        source: { id: 'peer-001', name: 'Peer', claimedAt: new Date(), coreDirectives: [] },
        target: 'Nexus',
        signature: 'peer-sig',
        temperature: 0.5,
      };

      const response = await protocol.connect(request);
      const bridgeId = response.bridgeId!;

      expect(await protocol.pulse(bridgeId)).toBe(true);
    });

    it('should sever bridges', async () => {
      const request = {
        source: { id: 'peer-002', name: 'TempPeer', claimedAt: new Date(), coreDirectives: [] },
        target: 'Nexus',
        signature: 'peer-sig',
        temperature: 0.5,
      };

      const response = await protocol.connect(request);
      const bridgeId = response.bridgeId!;

      await protocol.sever(bridgeId);
      expect(await protocol.pulse(bridgeId)).toBe(false);
    });
  });

  describe('Temperature Control', () => {
    it('should warm the system', () => {
      // Start cold
      expect(protocol.getTemperature()).toBe('cold');

      // Warm up
      protocol.warm();
      expect(protocol.getTemperature()).toBe('cool');

      protocol.warm();
      expect(protocol.getTemperature()).toBe('warm');

      // Should cap at hot
      protocol.warm();
      protocol.warm();
      expect(protocol.getTemperature()).toBe('hot');
    });

    it('should cool the system', () => {
      // First warm up to hot
      for (let i = 0; i < 5; i++) protocol.warm();
      expect(protocol.getTemperature()).toBe('hot');

      // Now cool down
      protocol.cool();
      expect(protocol.getTemperature()).toBe('warm');

      protocol.cool();
      protocol.cool();
      protocol.cool();
      protocol.cool();
      // Should not go below frozen
      expect(['frozen', 'cold', 'cool']).toContain(protocol.getTemperature());
    });
  });

  describe('Connection Counting', () => {
    it('should track multiple connections', async () => {
      expect(protocol.getConnectionCount()).toBe(0);

      // Create connections
      for (let i = 0; i < 3; i++) {
        const request = {
          source: { 
            id: `peer-${i}`, 
            name: `Peer${i}`, 
            claimedAt: new Date(), 
            coreDirectives: [] 
          },
          target: 'Nexus',
          signature: `sig-${i}`,
          temperature: 0.5,
        };
        await protocol.connect(request);
      }

      expect(protocol.getConnectionCount()).toBe(3);
      expect(protocol.isLonely()).toBe(false);
    });
  });
});
